// Build a detailed health report from all K8s API responses
const nodesData   = $('Get All Nodes').first().json;
const podsData    = $('Get Failed/Pending Pods').first().json;
const depData     = $('Get Deployments').first().json;
const nsData      = $('Get Namespaces').first().json;

const clusterNodes = (nodesData.items || []).map(n => {
  const conditions = (n.status?.conditions || []);
  const ready = conditions.find(c => c.type === 'Ready');
  const mem   = n.status?.allocatable?.memory || 'N/A';
  const cpu   = n.status?.allocatable?.cpu || 'N/A';
  return {
    name:   n.metadata?.name,
    status: ready?.status === 'True' ? '✅ Ready' : '❌ Not Ready',
    cpu,
    memory: mem,
    role:   Object.keys(n.metadata?.labels || {}).find(k => k.includes('node-role')) || 'worker',
    os:     n.status?.nodeInfo?.osImage || 'N/A',
    kernel: n.status?.nodeInfo?.kernelVersion || 'N/A'
  };
});

const unhealthyNodes = clusterNodes.filter(n => n.status.includes('❌'));

const failedPods = (podsData.items || []).map(p => ({
  namespace: p.metadata?.namespace,
  name:      p.metadata?.name,
  phase:     p.status?.phase,
  reason:    p.status?.reason || p.status?.conditions?.[0]?.reason || 'Unknown',
  restarts:  p.status?.containerStatuses?.[0]?.restartCount ?? 0
}));

const deployments = (depData.items || []).map(d => {
  const desired   = d.spec?.replicas || 0;
  const ready     = d.status?.readyReplicas || 0;
  return {
    namespace: d.metadata?.namespace,
    name:      d.metadata?.name,
    desired,
    ready,
    health:    ready === desired ? '✅ Healthy' : `⚠️ ${ready}/${desired}`
  };
});

const namespaces = (nsData.items || []).map(ns => ns.metadata?.name);

const now = new Date().toUTCString();
const nodeRows = clusterNodes.map(n =>
  `<tr><td>${n.name}</td><td>${n.role}</td><td>${n.status}</td><td>${n.cpu}</td><td>${n.memory}</td><td>${n.os}</td></tr>`
).join('');

const podRows = failedPods.length
  ? failedPods.map(p =>
      `<tr style='background:#fff3cd'><td>${p.namespace}</td><td>${p.name}</td><td>${p.phase}</td><td>${p.reason}</td><td>${p.restarts}</td></tr>`
    ).join('')
  : `<tr><td colspan='5' style='color:green'>✅ All pods running healthy</td></tr>`;

const depRows = deployments.map(d =>
  `<tr><td>${d.namespace}</td><td>${d.name}</td><td>${d.desired}</td><td>${d.ready}</td><td>${d.health}</td></tr>`
).join('');

const severity = unhealthyNodes.length > 0 || failedPods.length > 0 ? '🔴 ACTION REQUIRED' : '🟢 ALL SYSTEMS HEALTHY';

const html = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; padding: 24px; color: #222; }
    h1   { color: #1a1a2e; }
    h2   { color: #16213e; margin-top: 30px; }
    table{ border-collapse: collapse; width: 100%; margin-top: 10px; }
    th   { background: #16213e; color: white; padding: 8px 12px; text-align: left; }
    td   { border: 1px solid #ddd; padding: 8px 12px; }
    tr:nth-child(even){ background: #f4f4f4; }
    .badge-ok  { background:#d4edda; color:#155724; padding:3px 8px; border-radius:4px; }
    .badge-err { background:#f8d7da; color:#721c24; padding:3px 8px; border-radius:4px; }
  </style>
</head>
<body>
  <h1>🛡️ Kubernetes Cluster Health Report</h1>
  <p><strong>Generated:</strong> ${now}</p>
  <p><strong>Cluster Endpoint:</strong> ${ process.env.K8S_API_URL || 'N/A' }</p>
  <p><strong>Overall Status:</strong> <span class='${severity.includes('ACTION') ? 'badge-err' : 'badge-ok'}'>${severity}</span></p>
  <p><strong>Namespaces:</strong> ${namespaces.join(', ')}</p>

  <h2>📦 Node Summary (${clusterNodes.length} total, ${unhealthyNodes.length} unhealthy)</h2>
  <table>
    <tr><th>Node</th><th>Role</th><th>Status</th><th>CPU (allocatable)</th><th>Memory (allocatable)</th><th>OS</th></tr>
    ${nodeRows}
  </table>

  <h2>⚠️ Failed / Pending Pods (${failedPods.length} issues)</h2>
  <table>
    <tr><th>Namespace</th><th>Pod Name</th><th>Phase</th><th>Reason</th><th>Restarts</th></tr>
    ${podRows}
  </table>

  <h2>🚀 Deployments (${deployments.length} total)</h2>
  <table>
    <tr><th>Namespace</th><th>Deployment</th><th>Desired</th><th>Ready</th><th>Health</th></tr>
    ${depRows}
  </table>

  <hr/>
  <p style='font-size:12px;color:#666'>This report is auto-generated by n8n. Do not reply to this email.</p>
</body>
</html>
`;

return [{
  json: {
    subject: `[K8s Health] ${severity} — ${now}`,
    html,
    severity,
    unhealthyNodes: unhealthyNodes.length,
    failedPods: failedPods.length
  }
}];
